tasks.named<DependencyUpdatesTask>("dependencyUpdates").configure {
    rejectVersionIf {
        val stableKeyword = listOf("RELEASE", "FINAL", "GA").any { candidate.version.uppercase().contains(it) }
        val regex = "^[0-9,.v-]+(-r)?$".toRegex()
        val isStable = stableKeyword || regex.matches(candidate.version)
        !isStable
    }
}

tasks.named<com.github.benmanes.gradle.versions.updates.DependencyUpdatesTask>("dependencyUpdates") {
    notCompatibleWithConfigurationCache("gradle-versions-plugin invokes JavaBasePlugin at execution time")
}

tasks.named<com.github.benmanes.gradle.versions.updates.DependencyUpdatesTask>("dependencyUpdates").configure {
    filterConfigurations = org.gradle.api.specs.Spec<Configuration> { 
        !it.name.startsWith("incrementalScalaAnalysis") 
    }
}